ee:message.ee:set-payload:
%dw 2.0
output application/json


fun splitPartyName(partyName) = do {
    var parts = partyName splitBy " "
    ---
    {
        firstName: parts[0] default "",
        lastName:  (parts[1 to -1] joinBy " ") default ""
    }
}

fun buildBackendAddress(partyAddress) = {
    street: partyAddress.addressLine1,
    city:   partyAddress.addressCityName,
    state:  partyAddress.addressStateProvince,
    zip:    partyAddress.addressPostalCode
}


fun buildProfileAddress(addr, involvementType) = {
    "type":        if (involvementType == "EDUCATION") "school" else "employment",
    addressLine: addr.addressLine1,
    city:        addr.addressCityName,
    state:       addr.addressStateProvince,
    postalCode:  addr.addressPostalCode,
    country:     addr.addressCountryCode
}


fun buildUSCitizenCitizenship(partyIdentification) = {
    status:     "us_citizen",
    ssnOrItin:  partyIdentification.partyIdentificationRecord.partyIdentificationValue
}


fun buildNonUSCitizenship(partyIdentification) = {
    status:     "non_us",

    ssnOrItin:
        if (partyIdentification.partyTaxIdentificationRecord == null) null
        else partyIdentification.partyTaxIdentificationRecord.partyIdentificationValue,
    passport: {
        number:         partyIdentification.partyIdentificationRecord.partyIdentificationValue,
        country:        partyIdentification.partyIdentificationRecord.partyIdentificationIssuingCountry,
        issuanceDate:   partyIdentification.partyIdentificationRecord.partyIdentificationIssueDate,
        expirationDate: partyIdentification.partyIdentificationRecord.partyIdentificationExpiryDate
    },
    visa: {
        'type':       partyIdentification.partyVisaRecord.partyVisaType,
        number:     partyIdentification.partyVisaRecord.partyVisaNumber,
        issueDate:  partyIdentification.partyVisaRecord.partyVisaIssueDate,
        expiryDate: partyIdentification.partyVisaRecord.partyVisaExpiryDate
    },
    otherGovernmentIds:
        (partyIdentification.otherPartyIdentificationRecords default []) map (rec) -> {
            idType:  rec.partyIdentificationType,
            idValue: rec.partyIdentificationValue
        }
}


fun buildAdditionalProfiles(partyInvolvement) =
    (partyInvolvement default []) map (involvement) ->
        if (involvement.partyInvolvementType == "EDUCATION")

            {
                profileType:        "student",
                universityName:     involvement.partyInvolvementRecord.institutionName,
                studentId:          involvement.partyInvolvementRecord.institutionStudentReference,
                i20Number:          involvement.partyInvolvementRecord.studentVisaDocumentReference default "",
                expectedGraduation: involvement.partyInvolvementRecord.partyInvolvementEndDate,
                addresses: (involvement.partyInvolvementRecord.partyInvolvementAddress default [])
                    map (addr) -> buildProfileAddress(addr, "EDUCATION")
            }
        else

            {
                profileType:      "employment",
                organizationName: involvement.partyInvolvementRecord.institutionName,
                h1bOrEadNumber:   involvement.partyInvolvementRecord.employmentVisaDocumentReference default "",
                employmentStart:  involvement.partyInvolvementRecord.partyInvolvementStartDate,
                addresses: (involvement.partyInvolvementRecord.partyInvolvementAddress default [])
                    map (addr) -> buildProfileAddress(addr, "EMPLOYMENT")
            }


var nameparts = splitPartyName(payload.partyRecord.partyName)
---
{

    caseId: payload.onboardingCaseReference,


    customer: {
        firstName:   nameparts.firstName,
        lastName:    nameparts.lastName,
        email:       payload.partyRecord.partyContactDetails.partyContactEmailAddress default null,
        phone:       payload.partyRecord.partyContactDetails.partyContactPhone default null,
        dateOfBirth: payload.partyRecord.partyDateOfBirth,
        country:     payload.partyRecord.partyNationality,
        address:     buildBackendAddress(payload.partyRecord.partyAddress)
    },


    citizenship:
        if (payload.partyIdentification.partyLegalStatus == "us_citizen")
            buildUSCitizenCitizenship(payload.partyIdentification)
        else
            buildNonUSCitizenship(payload.partyIdentification),


    additionalProfiles: buildAdditionalProfiles(payload.partyInvolvement)
}
